        {
            QuemCad = QuemCadValue,
            LogicalOperator = " AND "
        };
        // Act
        var result = _serviceS.WFiltroReuniao(filtro);
        // Assert
        result.Should().NotBeNull();
        // Check parameter
        var QuemCadParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBReuniaoDicInfo.QuemCad}");
